import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const fmtPct = (v) => v == null ? "--" : `${v.toFixed(1)}%`;
const fmtMB  = (v) => v == null ? "--" : v >= 1024 ? `${(v / 1024).toFixed(1)} GB` : `${v} MB`;

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── progress bar ────────────────────────────────────── */
function ProgressBar({ label, value, max = 100, unit = "%", color }) {
  const pct = Math.min((max > 0 ? value / max : 0) * 100, 100);
  const barColor = color || (pct > 90 ? "var(--v2-red)" : pct > 70 ? "var(--v2-amber)" : "var(--v2-green)");
  return (
    <div style={{ marginBottom: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
        <span>{label}</span>
        <span className="v2-mono" style={{ color: barColor }}>{(value ?? 0).toFixed(1)}{unit}</span>
      </div>
      <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
        <div style={{ height: "100%", width: `${pct}%`, borderRadius: 6, background: barColor, transition: "width 0.4s ease" }} />
      </div>
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function Resources() {
  const { state } = useAppStore();

  /* poll system health */
  const { data: healthData, loading } = usePoll(
    async () => { const r = await http.get("/system/health"); return r.data; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  /* derive resource data from healthData */
  const cpu = healthData?.cpu ?? null;
  const memoryGB = healthData?.memory_gb ?? healthData?.memoryGB ?? null;
  const disk = healthData?.disk ?? null;
  const gpu = healthData?.gpu ?? null;

  const processes = healthData?.processes ?? [];
  const cpuHistory = healthData?.cpu_history ?? healthData?.cpuHistory ?? [];
  const memAlloc = healthData?.mem_alloc ?? healthData?.memAlloc ?? [];
  const diskPartitions = healthData?.disk_partitions ?? healthData?.diskPartitions ?? [];
  const top10 = healthData?.top_processes ?? healthData?.topProcesses ?? [];

  const totalMem = memAlloc.length > 0 ? memAlloc.reduce((a, b) => a + (b.mem || 0), 0) : 0;

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Resource Utilization</h1>
            <div className="v2-muted">Loading resource data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      {/* header */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Resource Utilization</h1>
          <div className="v2-muted">CPU, memory, disk, and inference metrics per bot and service.</div>
        </div>
      </div>

      {/* top stats */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Total CPU %" value={cpu != null ? fmtPct(cpu) : "--"} t={cpu != null && cpu > 80 ? "red" : "green"} sub="Aggregate utilization" />
        <Stat label="Total Memory" value={memoryGB != null ? `${memoryGB} GB` : "--"} t="blue" sub="Allocated across all" />
        <Stat label="Disk Used %" value={disk != null ? fmtPct(disk) : "--"} t={disk != null && disk > 80 ? "amber" : "green"} sub="Primary partition" />
        <Stat label="GPU Util %" value={gpu != null && gpu > 0 ? fmtPct(gpu) : "--"} t="blue" sub={gpu != null && gpu > 0 ? "Active" : "No GPU detected"} />
      </div>

      {/* per-bot resource table */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Per-Process Resource Usage</div>
          {processes.length === 0 ? (
            <V2EmptyState title="No Process Data" message="Per-process resource data will appear once reported by the system health API." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "160px 80px 100px 80px 90px 100px" }}>
                <span>Process</span>
                <span>CPU %</span>
                <span>Memory</span>
                <span>Threads</span>
                <span>Open Files</span>
                <span>Network I/O</span>
              </div>
              {processes.map(p => {
                const cpuAlert = p.cpu > 80;
                const memAlert = p.mem > 900;
                return (
                  <div key={p.name} className="v2-tr" style={{
                    gridTemplateColumns: "160px 80px 100px 80px 90px 100px",
                    background: cpuAlert || memAlert ? "rgba(255,120,120,0.04)" : "transparent",
                  }}>
                    <span style={{ fontWeight: 600 }}>
                      {p.name}
                      {cpuAlert && <span className="v2-red" style={{ fontSize: 10, marginLeft: 8 }}>CPU HIGH</span>}
                    </span>
                    <span className={`v2-mono v2-${p.cpu > 80 ? "red" : p.cpu > 60 ? "amber" : "green"}`}>{fmtPct(p.cpu)}</span>
                    <span className="v2-mono">{fmtMB(p.mem)}</span>
                    <span className="v2-mono">{p.threads ?? "--"}</span>
                    <span className="v2-mono">{p.openFiles ?? "--"}</span>
                    <span className="v2-mono">{p.netIO ?? "--"}</span>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* CPU over time + Memory allocation */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">CPU Usage (Last Hour Average)</div>
          {cpuHistory.length === 0 ? (
            <V2EmptyState title="No CPU History" message="CPU usage history will appear once the system health API reports it." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {cpuHistory.map(p => (
                <div key={p.name} style={{ marginBottom: 12 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                    <span>{p.name}</span>
                    <span className="v2-mono">avg {p.avg}% / peak {p.peak}%</span>
                  </div>
                  <div style={{ height: 8, borderRadius: 6, background: "rgba(255,255,255,0.04)", position: "relative" }}>
                    <div style={{
                      height: "100%", width: `${p.avg}%`, borderRadius: 6,
                      background: p.color || "rgba(150,190,255,0.8)", transition: "width 0.4s ease",
                    }} />
                    <div style={{
                      position: "absolute", top: 0, left: `${p.peak}%`,
                      width: 2, height: "100%", background: "rgba(255,255,255,0.4)",
                    }} title={`Peak: ${p.peak}%`} />
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Memory Allocation</div>
          {memAlloc.length === 0 ? (
            <V2EmptyState title="No Memory Data" message="Memory allocation breakdown will appear once reported by the API." />
          ) : (
            <div style={{ marginTop: 12 }}>
              <div style={{ display: "flex", height: 28, borderRadius: 6, overflow: "hidden", background: "rgba(255,255,255,0.04)" }}>
                {memAlloc.map(m => (
                  <div key={m.name} style={{
                    width: `${(m.mem / totalMem) * 100}%`,
                    background: m.color || "rgba(150,190,255,0.8)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 10, fontWeight: 600, overflow: "hidden", whiteSpace: "nowrap",
                  }} title={`${m.name}: ${fmtMB(m.mem)}`}>
                    {(m.mem / totalMem) * 100 > 12 ? m.name : ""}
                  </div>
                ))}
              </div>
              {/* legend */}
              <div style={{ display: "flex", flexWrap: "wrap", gap: 12, marginTop: 12 }}>
                {memAlloc.map(m => (
                  <div key={m.name} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 11 }}>
                    <span style={{ width: 10, height: 10, borderRadius: 6, background: m.color || "rgba(150,190,255,0.8)", display: "inline-block" }} />
                    <span>{m.name}</span>
                    <span className="v2-mono v2-muted">{fmtMB(m.mem)}</span>
                  </div>
                ))}
              </div>
              <div style={{ marginTop: 12, borderTop: "1px solid rgba(255,255,255,0.06)", paddingTop: 8 }}>
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13 }}>
                  <span>Total Allocated</span>
                  <span className="v2-mono" style={{ fontWeight: 700 }}>{fmtMB(totalMem)}</span>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* disk usage */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Disk Usage</div>
          {diskPartitions.length === 0 ? (
            <V2EmptyState title="No Disk Data" message="Disk partition data will appear once reported by the system health API." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "100px 100px 100px 100px 80px 120px" }}>
                <span>Partition</span>
                <span>Total</span>
                <span>Used</span>
                <span>Free</span>
                <span>%</span>
                <span>Mount Point</span>
              </div>
              {diskPartitions.map(d => (
                <div key={d.partition} className="v2-tr" style={{ gridTemplateColumns: "100px 100px 100px 100px 80px 120px" }}>
                  <span className="v2-mono">{d.partition}</span>
                  <span className="v2-mono">{d.total}</span>
                  <span className="v2-mono">{d.used}</span>
                  <span className="v2-mono">{d.free}</span>
                  <span className={`v2-mono v2-${d.pct > 80 ? "red" : d.pct > 60 ? "amber" : "green"}`}>{fmtPct(d.pct)}</span>
                  <span className="v2-mono v2-muted">{d.mount}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* process list */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">Top 10 Processes by Resource Usage</div>
          {top10.length === 0 ? (
            <V2EmptyState title="No Process Data" message="Top process data will appear once reported by the system health API." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "60px 280px 80px 100px" }}>
                <span>PID</span>
                <span>Process</span>
                <span>CPU %</span>
                <span>Memory</span>
              </div>
              {top10.map(p => (
                <div key={p.pid} className="v2-tr" style={{
                  gridTemplateColumns: "60px 280px 80px 100px",
                  background: p.cpu > 80 || p.mem > 900 ? "rgba(255,120,120,0.04)" : "transparent",
                }}>
                  <span className="v2-mono v2-muted">{p.pid}</span>
                  <span>{p.name}</span>
                  <span className={`v2-mono v2-${p.cpu > 80 ? "red" : p.cpu > 60 ? "amber" : "green"}`}>{fmtPct(p.cpu)}</span>
                  <span className={`v2-mono v2-${p.mem > 900 ? "red" : p.mem > 500 ? "amber" : "blue"}`}>{fmtMB(p.mem)}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
